-- Module: user-management, File: 300_20260227_rlsgrants.sql
-- ---------------------------
-- MODULE NAME: User Management
-- MODULE DATE: 20260227
-- MODULE SCOPE: RLS & Grants
-- ---------------------------

BEGIN;

-- ---------------------------
-- Helper: check super admin (bypasses RLS; used by config and other modules)
-- ---------------------------

CREATE OR REPLACE FUNCTION public.is_super_admin(user_auth_id UUID)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    is_admin BOOLEAN;
BEGIN
    SELECT is_super_admin INTO is_admin
    FROM public.users
    WHERE auth_id = user_auth_id
    LIMIT 1;
    RETURN COALESCE(is_admin, false);
END;
$$;

GRANT EXECUTE ON FUNCTION public.is_super_admin(UUID) TO authenticated;
COMMENT ON FUNCTION public.is_super_admin(UUID) IS 'Check if a user is a super admin (bypasses RLS to avoid recursion)';

-- ---------------------------
-- Users
-- ---------------------------

-- Anon: public profile columns only (no verification tokens)
GRANT SELECT (id, full_name, email, is_email_verified, is_super_admin, created_at, updated_at) ON public.users TO anon;

-- Authenticated: full access (restricted by RLS)
GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.users TO authenticated;
GRANT SELECT (email_verification_token, email_verification_token_expires) ON public.users TO authenticated;

-- Service role
GRANT DELETE, INSERT, REFERENCES, SELECT, TRUNCATE, UPDATE, TRIGGER ON public.users TO service_role;

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Authenticated users can view their own data" ON public.users;
CREATE POLICY "Authenticated users can view their own data"
ON public.users
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (auth_id = auth.uid());

DROP POLICY IF EXISTS "Owners can update their profiles" ON public.users;
CREATE POLICY "Owners can update their profiles"
ON public.users
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (auth_id = auth.uid())
WITH CHECK (auth_id = auth.uid());

DROP POLICY IF EXISTS "Anon users can view public profiles" ON public.users;
CREATE POLICY "Anon users can view public profiles"
ON public.users
AS PERMISSIVE
FOR SELECT
TO anon
USING (true);

-- Super admins can view and update any user (e.g. for admin tooling)
DROP POLICY IF EXISTS "Super admins can update any user data" ON public.users;
CREATE POLICY "Super admins can update any user data"
ON public.users
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (public.is_super_admin(auth.uid()))
WITH CHECK (public.is_super_admin(auth.uid()));

DROP POLICY IF EXISTS "Super admins can view all user data" ON public.users;
CREATE POLICY "Super admins can view all user data"
ON public.users
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (public.is_super_admin(auth.uid()));

-- ---------------------------
-- User Profiles
-- ---------------------------

GRANT SELECT ON public.user_profiles TO anon;
GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.user_profiles TO authenticated;
GRANT DELETE, INSERT, REFERENCES, SELECT, TRUNCATE, UPDATE, TRIGGER ON public.user_profiles TO service_role;

ALTER TABLE public.user_profiles ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "User profiles are publicly accessible" ON public.user_profiles;
CREATE POLICY "User profiles are publicly accessible"
ON public.user_profiles
AS PERMISSIVE
FOR SELECT
TO public
USING (true);

DROP POLICY IF EXISTS "Owners can update their own profiles" ON public.user_profiles;
CREATE POLICY "Owners can update their own profiles"
ON public.user_profiles
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.users
        WHERE users.id = user_profiles.owner_id
        AND users.auth_id = auth.uid()
    )
)
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.users
        WHERE users.id = user_profiles.owner_id
        AND users.auth_id = auth.uid()
    )
);

DROP POLICY IF EXISTS "Owners can insert their own profiles" ON public.user_profiles;
CREATE POLICY "Owners can insert their own profiles"
ON public.user_profiles
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.users
        WHERE users.id = user_profiles.owner_id
        AND users.auth_id = auth.uid()
    )
);

DROP POLICY IF EXISTS "Super admins can manage any profile" ON public.user_profiles;
CREATE POLICY "Super admins can manage any profile"
ON public.user_profiles
AS PERMISSIVE
FOR ALL
TO authenticated
USING (public.is_super_admin(auth.uid()))
WITH CHECK (public.is_super_admin(auth.uid()));

-- ---------------------------
-- Avatars (storage.objects for bucket 'avatars')
-- ---------------------------

GRANT SELECT ON storage.objects TO anon;
GRANT DELETE, INSERT, REFERENCES, SELECT, TRUNCATE, UPDATE, TRIGGER ON storage.objects TO authenticated;
GRANT DELETE, INSERT, REFERENCES, SELECT, TRUNCATE, UPDATE, TRIGGER ON storage.objects TO service_role;

DROP POLICY IF EXISTS "Allow authenticated users to upload their own avatar." ON storage.objects;
CREATE POLICY "Allow authenticated users to upload their own avatar."
ON storage.objects
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (
    bucket_id = 'avatars'::text
    AND auth.uid() = owner
);

DROP POLICY IF EXISTS "Allow authenticated users to update their own avatar." ON storage.objects;
CREATE POLICY "Allow authenticated users to update their own avatar."
ON storage.objects
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (
    bucket_id = 'avatars'::text
    AND auth.uid() = owner
)
WITH CHECK (
    bucket_id = 'avatars'::text
    AND auth.uid() = owner
);

DROP POLICY IF EXISTS "Allow admin users to delete their own avatar." ON storage.objects;
CREATE POLICY "Allow admin users to delete their own avatar."
ON storage.objects
AS PERMISSIVE
FOR DELETE
TO authenticated
USING (
    bucket_id = 'avatars'::text
    AND auth.uid() = owner
);

DROP POLICY IF EXISTS "Avatar images are publicly accessible." ON storage.objects;
CREATE POLICY "Avatar images are publicly accessible."
ON storage.objects
AS PERMISSIVE
FOR SELECT
TO anon, authenticated
USING (bucket_id = 'avatars'::text);

DROP POLICY IF EXISTS "Allow service_role to manage avatars" ON storage.objects;
CREATE POLICY "Allow service_role to manage avatars"
ON storage.objects
AS PERMISSIVE
FOR ALL
TO service_role
USING (bucket_id = 'avatars'::text);

-- ---------------------------
-- END OF FILE
-- ---------------------------


-- Module: user-auth, File: 301_20260227_rlsgrants.sql
-- ---------------------------
-- MODULE NAME: User Auth
-- MODULE DATE: 20260227
-- MODULE SCOPE: RLS & Grants
-- ---------------------------

BEGIN;

-- ---------------------------
-- refresh_tokens RLS
-- ---------------------------

ALTER TABLE public.refresh_tokens ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Users can view their own refresh tokens" ON public.refresh_tokens;
CREATE POLICY "Users can view their own refresh tokens"
ON public.refresh_tokens
FOR SELECT
USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can revoke their own refresh tokens" ON public.refresh_tokens;
CREATE POLICY "Users can revoke their own refresh tokens"
ON public.refresh_tokens
FOR UPDATE
USING (user_id = auth.uid());

DROP POLICY IF EXISTS "Users can insert their own refresh tokens" ON public.refresh_tokens;
CREATE POLICY "Users can insert their own refresh tokens"
ON public.refresh_tokens
FOR INSERT
WITH CHECK (user_id = auth.uid());

DROP POLICY IF EXISTS "Service roles can manage refresh tokens" ON public.refresh_tokens;
CREATE POLICY "Service roles can manage refresh tokens"
ON public.refresh_tokens
FOR ALL
USING (auth.role() = 'service_role');

-- ---------------------------
-- Comments
-- ---------------------------

COMMENT ON TABLE public.refresh_tokens IS 'Stores refresh tokens for JWT authentication';
COMMENT ON COLUMN public.refresh_tokens.id IS 'Unique identifier for the refresh token record';
COMMENT ON COLUMN public.refresh_tokens.user_id IS 'Reference to the user this token belongs to';
COMMENT ON COLUMN public.refresh_tokens.token IS 'The actual refresh token (hashed)';
COMMENT ON COLUMN public.refresh_tokens.created_at IS 'When the token was created';
COMMENT ON COLUMN public.refresh_tokens.expires_at IS 'When the token expires';
COMMENT ON COLUMN public.refresh_tokens.revoked IS 'Whether the token has been revoked';
COMMENT ON COLUMN public.refresh_tokens.revoked_at IS 'When the token was revoked, if applicable';
COMMENT ON COLUMN public.refresh_tokens.replaced_by IS 'Reference to the token that replaced this one (token rotation)';
COMMENT ON COLUMN public.refresh_tokens.ip_address IS 'IP address where the token was issued';
COMMENT ON COLUMN public.refresh_tokens.user_agent IS 'Browser/device information where the token was issued';

-- ---------------------------
-- END OF FILE
-- ---------------------------


-- Module: organization, File: 301_20260309_rlsgrants.sql
-- ---------------------------
-- MODULE NAME: Organization
-- MODULE DATE: 20260309
-- MODULE SCOPE: RLS & Grants
-- ---------------------------

BEGIN;

-- ---------------------------
-- Grants
-- ---------------------------

GRANT SELECT, INSERT, UPDATE, DELETE ON public.organizations TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.user_organizations TO authenticated;
GRANT USAGE ON TYPE public.workspace_membership_role TO authenticated;

GRANT SELECT, INSERT, UPDATE, DELETE ON public.organizations TO service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.user_organizations TO service_role;

GRANT SELECT, INSERT, DELETE ON public.organization_invites TO authenticated;
GRANT SELECT, INSERT, DELETE ON public.organization_invites TO service_role;

-- ---------------------------
-- RLS: organizations
-- ---------------------------

ALTER TABLE public.organizations ENABLE ROW LEVEL SECURITY;

-- Users can view organizations they are a member of
DROP POLICY IF EXISTS "Members can view organization" ON public.organizations;
CREATE POLICY "Members can view organization"
ON public.organizations
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.user_organizations uo
        JOIN public.users u ON u.id = uo.user_id
        WHERE uo.organization_id = organizations.id
          AND u.auth_id = auth.uid()
          AND (uo.disabled = FALSE)
    )
);

-- Only org members with admin or owner can update
DROP POLICY IF EXISTS "Admins can update organization" ON public.organizations;
CREATE POLICY "Admins can update organization"
ON public.organizations
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.user_organizations uo
        JOIN public.users u ON u.id = uo.user_id
        WHERE uo.organization_id = organizations.id
          AND u.auth_id = auth.uid()
          AND (uo.disabled = FALSE)
          AND uo.role IN ('admin', 'owner')
    )
)
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.user_organizations uo
        JOIN public.users u ON u.id = uo.user_id
        WHERE uo.organization_id = organizations.id
          AND u.auth_id = auth.uid()
          AND (uo.disabled = FALSE)
          AND uo.role IN ('admin', 'owner')
    )
);

-- Authenticated users can create organizations (membership is added in app layer)
DROP POLICY IF EXISTS "Authenticated can create organization" ON public.organizations;
CREATE POLICY "Authenticated can create organization"
ON public.organizations
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (true);

-- Only owner members can delete (optional; we may disallow delete in app)
DROP POLICY IF EXISTS "Superadmin can delete organization" ON public.organizations;
CREATE POLICY "Superadmin can delete organization"
ON public.organizations
AS PERMISSIVE
FOR DELETE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.user_organizations uo
        JOIN public.users u ON u.id = uo.user_id
        WHERE uo.organization_id = organizations.id
          AND u.auth_id = auth.uid()
          AND (uo.disabled = FALSE)
          AND uo.role = 'owner'
    )
);

-- ---------------------------
-- RLS: user_organizations
-- ---------------------------

ALTER TABLE public.user_organizations ENABLE ROW LEVEL SECURITY;

-- Members can view memberships of their organizations
DROP POLICY IF EXISTS "Members can view user_organizations" ON public.user_organizations;
CREATE POLICY "Members can view user_organizations"
ON public.user_organizations
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.user_organizations self
        JOIN public.users u ON u.id = self.user_id
        WHERE self.organization_id = user_organizations.organization_id
          AND u.auth_id = auth.uid()
          AND (self.disabled = FALSE)
    )
);

-- Admins/owners can insert (add member) into user_organizations
DROP POLICY IF EXISTS "Admins can add team member" ON public.user_organizations;
CREATE POLICY "Admins can add team member"
ON public.user_organizations
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.user_organizations self
        JOIN public.users u ON u.id = self.user_id
        WHERE self.organization_id = user_organizations.organization_id
          AND u.auth_id = auth.uid()
          AND (self.disabled = FALSE)
          AND self.role IN ('admin', 'owner')
    )
);

-- Admins can update (e.g. role, disabled) for non-owner members; users can update own disabled
DROP POLICY IF EXISTS "Admins can update membership" ON public.user_organizations;
CREATE POLICY "Admins can update membership"
ON public.user_organizations
AS PERMISSIVE
FOR UPDATE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.user_organizations self
        JOIN public.users u ON u.id = self.user_id
        WHERE self.organization_id = user_organizations.organization_id
          AND u.auth_id = auth.uid()
          AND (self.disabled = FALSE)
          AND self.role IN ('admin', 'owner')
    )
)
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.user_organizations self
        JOIN public.users u ON u.id = self.user_id
        WHERE self.organization_id = user_organizations.organization_id
          AND u.auth_id = auth.uid()
          AND (self.disabled = FALSE)
          AND self.role IN ('admin', 'owner')
    )
);

-- Admins can delete (remove member) other members; users can delete own membership
DROP POLICY IF EXISTS "Admins or self can delete membership" ON public.user_organizations;
CREATE POLICY "Admins or self can delete membership"
ON public.user_organizations
AS PERMISSIVE
FOR DELETE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.id = user_organizations.user_id AND u.auth_id = auth.uid()
    )
    OR EXISTS (
        SELECT 1 FROM public.user_organizations self
        JOIN public.users u ON u.id = self.user_id
        WHERE self.organization_id = user_organizations.organization_id
          AND u.auth_id = auth.uid()
          AND (self.disabled = FALSE)
          AND self.role IN ('admin', 'owner')
    )
);

-- ---------------------------
-- RLS: organization_invites
-- ---------------------------

ALTER TABLE public.organization_invites ENABLE ROW LEVEL SECURITY;

-- Invitee can see invites sent to their email
DROP POLICY IF EXISTS "Invitee can view own invites" ON public.organization_invites;
CREATE POLICY "Invitee can view own invites"
ON public.organization_invites
AS PERMISSIVE
FOR SELECT
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.auth_id = auth.uid()
          AND LOWER(u.email) = LOWER(organization_invites.email)
    )
);

-- Admins/owners of the org can create invites (send invitation)
DROP POLICY IF EXISTS "Admins can create invite" ON public.organization_invites;
CREATE POLICY "Admins can create invite"
ON public.organization_invites
AS PERMISSIVE
FOR INSERT
TO authenticated
WITH CHECK (
    EXISTS (
        SELECT 1 FROM public.user_organizations uo
        JOIN public.users u ON u.id = uo.user_id
        WHERE uo.organization_id = organization_invites.organization_id
          AND u.auth_id = auth.uid()
          AND (uo.disabled = FALSE)
          AND uo.role IN ('admin', 'owner')
    )
);

-- Invitee can delete their own invite (e.g. when accepting)
DROP POLICY IF EXISTS "Invitee can delete own invite" ON public.organization_invites;
CREATE POLICY "Invitee can delete own invite"
ON public.organization_invites
AS PERMISSIVE
FOR DELETE
TO authenticated
USING (
    EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.auth_id = auth.uid()
          AND LOWER(u.email) = LOWER(organization_invites.email)
    )
);

