-- Module: rbac, File: 401_20260311_functions.sql
-- ---------------------------
-- MODULE NAME: RBAC (Role-Based Access Control)
-- MODULE DATE: 20260311
-- MODULE SCOPE: Functions
-- ---------------------------
-- user_id in user_roles is public.users.id. auth.uid() is Supabase auth user id.
-- JWT callers: assign/remove must pass their own public.users.id; get/has_role scoped to self unless admin.
-- Service role (auth.uid() null): assign/remove still validated via actor UUID arg (backend).

-- Function to get all permissions for a user (by public.users.id)
CREATE OR REPLACE FUNCTION public.get_user_permissions(user_uuid UUID)
RETURNS TABLE (permission public.app_permission) AS $$
DECLARE
    caller_auth UUID := auth.uid();
    caller_internal UUID;
BEGIN
    IF caller_auth IS NOT NULL THEN
        caller_internal := (SELECT u.id FROM public.users u WHERE u.auth_id = caller_auth LIMIT 1);
        IF user_uuid IS DISTINCT FROM caller_internal THEN
            IF caller_internal IS NULL
                OR NOT (
                    public.is_super_admin(caller_auth)
                    OR EXISTS (
                        SELECT 1
                        FROM public.user_roles ur
                        WHERE ur.user_id = caller_internal AND ur.role = 'admin'
                    )
                )
            THEN
                RAISE EXCEPTION 'Not allowed to query permissions for another user';
            END IF;
        END IF;
    END IF;

    RETURN QUERY
    SELECT DISTINCT rp.permission
    FROM public.user_roles ur
    JOIN public.role_permissions rp ON ur.role = rp.role
    WHERE ur.user_id = user_uuid;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';

COMMENT ON FUNCTION public.get_user_permissions(UUID) IS 'Returns permissions for public.users.id. JWT callers may only query self unless admin/super_admin.';

-- Function to check if user has a specific role (by public.users.id)
CREATE OR REPLACE FUNCTION public.has_role(user_uuid UUID, check_role public.app_role)
RETURNS BOOLEAN AS $$
DECLARE
    caller_auth UUID := auth.uid();
    caller_internal UUID;
BEGIN
    IF caller_auth IS NOT NULL THEN
        caller_internal := (SELECT u.id FROM public.users u WHERE u.auth_id = caller_auth LIMIT 1);
        IF user_uuid IS DISTINCT FROM caller_internal THEN
            IF caller_internal IS NULL
                OR NOT (
                    public.is_super_admin(caller_auth)
                    OR EXISTS (
                        SELECT 1
                        FROM public.user_roles ur
                        WHERE ur.user_id = caller_internal AND ur.role = 'admin'
                    )
                )
            THEN
                RAISE EXCEPTION 'Not allowed to query roles for another user';
            END IF;
        END IF;
    END IF;

    RETURN EXISTS(
        SELECT 1 FROM public.user_roles
        WHERE user_id = user_uuid AND role = check_role
    );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';

COMMENT ON FUNCTION public.has_role(UUID, public.app_role) IS 'Check role for public.users.id. JWT callers may only query self unless admin/super_admin.';

-- Function to assign a role to a user. assigned_by_user_id is public.users.id.
CREATE OR REPLACE FUNCTION public.assign_user_role(
    target_user_id UUID,
    role_to_assign public.app_role,
    assigned_by_user_id UUID
)
RETURNS UUID AS $$
DECLARE
    new_role_id UUID;
    caller_auth UUID := auth.uid();
    actor_id UUID;
BEGIN
    IF caller_auth IS NOT NULL THEN
        actor_id := (SELECT u.id FROM public.users u WHERE u.auth_id = caller_auth LIMIT 1);
        IF actor_id IS NULL OR assigned_by_user_id IS DISTINCT FROM actor_id THEN
            RAISE EXCEPTION 'assigned_by_user_id must match the authenticated user';
        END IF;
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.id = assigned_by_user_id
        AND (
            u.is_super_admin = true
            OR EXISTS(
                SELECT 1 FROM public.user_roles ur
                WHERE ur.user_id = assigned_by_user_id AND ur.role = 'admin'
            )
        )
    ) THEN
        RAISE EXCEPTION 'Only admins can assign roles';
    END IF;

    INSERT INTO public.user_roles (user_id, role, created_by)
    VALUES (target_user_id, role_to_assign, assigned_by_user_id)
    ON CONFLICT (user_id, role) DO NOTHING
    RETURNING id INTO new_role_id;

    RETURN new_role_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';

COMMENT ON FUNCTION public.assign_user_role(UUID, public.app_role, UUID) IS 'Assigns a role. JWT callers must pass their own public.users.id as assigned_by_user_id; must be admin/super_admin.';

-- Function to remove a role from a user
CREATE OR REPLACE FUNCTION public.remove_user_role(
    target_user_id UUID,
    role_to_remove public.app_role,
    removed_by_user_id UUID
)
RETURNS BOOLEAN AS $$
DECLARE
    caller_auth UUID := auth.uid();
    actor_id UUID;
BEGIN
    IF caller_auth IS NOT NULL THEN
        actor_id := (SELECT u.id FROM public.users u WHERE u.auth_id = caller_auth LIMIT 1);
        IF actor_id IS NULL OR removed_by_user_id IS DISTINCT FROM actor_id THEN
            RAISE EXCEPTION 'removed_by_user_id must match the authenticated user';
        END IF;
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.id = removed_by_user_id
        AND (
            u.is_super_admin = true
            OR EXISTS(
                SELECT 1 FROM public.user_roles ur
                WHERE ur.user_id = removed_by_user_id AND ur.role = 'admin'
            )
        )
    ) THEN
        RAISE EXCEPTION 'Only admins can remove roles';
    END IF;

    DELETE FROM public.user_roles
    WHERE user_id = target_user_id AND role = role_to_remove;

    RETURN true;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';

COMMENT ON FUNCTION public.remove_user_role(UUID, public.app_role, UUID) IS 'Removes a role. JWT callers must pass their own public.users.id as removed_by_user_id; must be admin/super_admin.';

-- Grant execute to authenticated (must run after functions exist)
GRANT EXECUTE ON FUNCTION public.get_user_permissions(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION public.has_role(UUID, public.app_role) TO authenticated;
GRANT EXECUTE ON FUNCTION public.assign_user_role(UUID, public.app_role, UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION public.remove_user_role(UUID, public.app_role, UUID) TO authenticated;

-- ---------------------------
-- END OF FILE
-- ---------------------------


-- Module: blog, File: 401_20260313_functions.sql
-- ---------------------------
-- MODULE NAME: Blog System Functions
-- MODULE DATE: 20260313
-- MODULE SCOPE: Functions
-- ---------------------------

BEGIN;

-- ---------------------------
-- Update Updated At Function
-- ---------------------------
CREATE OR REPLACE FUNCTION public.update_blog_updated_at_column()
RETURNS TRIGGER 
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ language 'plpgsql';

-- Apply to all tables with updated_at
DROP TRIGGER IF EXISTS update_blog_posts_updated_at ON public.blog_posts;
CREATE TRIGGER update_blog_posts_updated_at
    BEFORE UPDATE ON public.blog_posts
    FOR EACH ROW
    EXECUTE FUNCTION public.update_blog_updated_at_column();

DROP TRIGGER IF EXISTS update_blog_topics_updated_at ON public.blog_topics;
CREATE TRIGGER update_blog_topics_updated_at
    BEFORE UPDATE ON public.blog_topics
    FOR EACH ROW
    EXECUTE FUNCTION public.update_blog_updated_at_column();

DROP TRIGGER IF EXISTS update_blog_comments_updated_at ON public.blog_comments;
CREATE TRIGGER update_blog_comments_updated_at
    BEFORE UPDATE ON public.blog_comments
    FOR EACH ROW
    EXECUTE FUNCTION public.update_blog_updated_at_column();

-- ---------------------------
-- Slug Generation
-- ---------------------------
CREATE OR REPLACE FUNCTION public.generate_unique_slug(title TEXT, table_name TEXT)
RETURNS TEXT
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    base_slug TEXT;
    new_slug TEXT;
    counter INTEGER := 1;
    slug_exists BOOLEAN;
BEGIN
    -- Convert title to lowercase and replace spaces and special chars with hyphens
    base_slug := lower(regexp_replace(title, '[^a-zA-Z0-9\\s]', '', 'g'));
    base_slug := regexp_replace(base_slug, '\\s+', '-', 'g');
    new_slug := base_slug;
    
    -- Check if slug exists in the specified table
    LOOP
        EXECUTE format('SELECT EXISTS(SELECT 1 FROM %I WHERE slug = $1)', table_name)
        INTO slug_exists
        USING new_slug;
        
        EXIT WHEN NOT slug_exists;
        
        counter := counter + 1;
        new_slug := base_slug || '-' || counter::text;
    END LOOP;
    
    RETURN new_slug;
END;
$$ LANGUAGE plpgsql;

-- ---------------------------
-- Auto-generate Slugs
-- ---------------------------
CREATE OR REPLACE FUNCTION public.generate_post_slug()
RETURNS TRIGGER
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    IF NEW.slug IS NULL THEN
        NEW.slug := public.generate_unique_slug(NEW.title, 'blog_posts');
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_post_slug ON public.blog_posts;
CREATE TRIGGER set_post_slug
    BEFORE INSERT ON public.blog_posts
    FOR EACH ROW
    EXECUTE FUNCTION public.generate_post_slug();

CREATE OR REPLACE FUNCTION public.generate_topic_slug()
RETURNS TRIGGER
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    IF NEW.slug IS NULL THEN
        NEW.slug := public.generate_unique_slug(NEW.name, 'blog_topics');
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_topic_slug ON public.blog_topics;
CREATE TRIGGER set_topic_slug
    BEFORE INSERT ON public.blog_topics
    FOR EACH ROW
    EXECUTE FUNCTION public.generate_topic_slug();

-- ---------------------------
-- Reading Time Calculation
-- ---------------------------
CREATE OR REPLACE FUNCTION public.calculate_blog_reading_time()
RETURNS TRIGGER
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    words_per_minute INTEGER := 200;
    word_count INTEGER;
BEGIN
    -- Count words in content (rough estimate)
    word_count := array_length(regexp_split_to_array(NEW.content, '\\s+'), 1);
    
    -- Calculate reading time in minutes (rounded up)
    NEW.reading_time_minutes := CEILING(word_count::float / words_per_minute);
    
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_reading_time ON public.blog_posts;
CREATE TRIGGER set_reading_time
    BEFORE INSERT OR UPDATE OF content ON public.blog_posts
    FOR EACH ROW
    EXECUTE FUNCTION public.calculate_blog_reading_time();

-- ---------------------------
-- Update Published At
-- ---------------------------
CREATE OR REPLACE FUNCTION public.update_blog_published_at()
RETURNS TRIGGER
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    IF NEW.is_admin_approved AND NEW.is_user_published AND OLD.published_at IS NULL THEN
        NEW.published_at = CURRENT_TIMESTAMP;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_published_at ON public.blog_posts;
CREATE TRIGGER set_published_at
    BEFORE UPDATE ON public.blog_posts
    FOR EACH ROW
    EXECUTE FUNCTION public.update_blog_published_at();

-- ---------------------------
-- Update View Count
-- ---------------------------
CREATE OR REPLACE FUNCTION public.increment_blog_view_count()
RETURNS TRIGGER
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    IF NEW.activity_type = 'view' THEN
        UPDATE public.blog_posts
        SET view_count = view_count + 1
        WHERE id = NEW.post_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS update_post_view_count ON public.blog_activities;
CREATE TRIGGER update_post_view_count
    AFTER INSERT ON public.blog_activities
    FOR EACH ROW
    EXECUTE FUNCTION public.increment_blog_view_count();

-- ---------------------------
-- Update Like Count
-- ---------------------------
CREATE OR REPLACE FUNCTION public.update_blog_post_like_count()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    IF (TG_OP = 'INSERT' AND NEW.activity_type = 'like') THEN
        UPDATE public.blog_posts
        SET like_count = like_count + 1
        WHERE id = NEW.post_id;
    ELSIF (TG_OP = 'DELETE' AND OLD.activity_type = 'like') THEN
        UPDATE public.blog_posts
        SET like_count = GREATEST(like_count - 1, 0)
        WHERE id = OLD.post_id;
    END IF;
    RETURN COALESCE(NEW, OLD);
END;
$$;

DROP TRIGGER IF EXISTS update_blog_post_like_count_trigger ON public.blog_activities;
CREATE TRIGGER update_blog_post_like_count_trigger
  AFTER INSERT OR DELETE ON public.blog_activities
  FOR EACH ROW
  EXECUTE FUNCTION public.update_blog_post_like_count();


-- Module: listing-categories, File: 401_20260628_functions.sql
-- ---------------------------
-- MODULE NAME: Listing Categories
-- MODULE DATE: 20260628
-- MODULE SCOPE: Functions
-- ---------------------------

BEGIN;

CREATE OR REPLACE FUNCTION public.get_active_listing_categories()
RETURNS TABLE (
    id UUID,
    name TEXT,
    slug TEXT,
    parent_path TEXT,
    listing_category_groups JSONB
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
    SELECT DISTINCT
        c.id,
        c.name,
        c.slug,
        c.parent_path,
        COALESCE(
            jsonb_agg(
                DISTINCT jsonb_build_object('id', cg.id, 'name', cg.name)
            ) FILTER (WHERE cg.id IS NOT NULL),
            '[]'::jsonb
        ) AS listing_category_groups
    FROM public.listing_categories c
    INNER JOIN public.listings l ON c.id = l.listing_category_id
        AND l.is_user_published = true
        AND l.is_admin_published = true
    LEFT JOIN public.listing_category_groups_listing_categories_association cgca ON c.id = cgca.listing_category_id
    LEFT JOIN public.listing_category_groups cg ON cgca.listing_category_group_id = cg.id
    GROUP BY c.id, c.name, c.slug, c.parent_path;
$$;

CREATE OR REPLACE FUNCTION public.get_full_active_listing_categories()
RETURNS TABLE (
    id UUID,
    name TEXT,
    slug TEXT,
    headline TEXT,
    description TEXT,
    image_url_hero TEXT,
    image_url_small TEXT,
    href TEXT,
    color TEXT,
    emoji TEXT,
    listing_category_groups JSONB
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
    SELECT
        c.id,
        c.name,
        c.slug,
        c.headline,
        c.description,
        c.image_url_hero,
        c.image_url_small,
        c.href,
        c.color,
        c.emoji,
        COALESCE(
            jsonb_agg(
                DISTINCT jsonb_build_object('id', cg.id, 'name', cg.name)
            ) FILTER (WHERE cg.id IS NOT NULL),
            '[]'::jsonb
        ) AS listing_category_groups
    FROM public.listing_categories c
    INNER JOIN public.listings l ON c.id = l.listing_category_id
        AND l.is_user_published = true
        AND l.is_admin_published = true
    LEFT JOIN public.listing_category_groups_listing_categories_association cgca ON c.id = cgca.listing_category_id
    LEFT JOIN public.listing_category_groups cg ON cgca.listing_category_group_id = cg.id
    GROUP BY
        c.id, c.name, c.slug, c.headline, c.description,
        c.image_url_hero, c.image_url_small, c.href, c.color, c.emoji;
$$;

GRANT EXECUTE ON FUNCTION public.get_active_listing_categories() TO anon, authenticated, service_role;
GRANT EXECUTE ON FUNCTION public.get_full_active_listing_categories() TO anon, authenticated, service_role;

